mapper.select:

	SELECT FRST_REGISTER_Id
	FROM XBOLTDLM.COMTNDAMKNOIFM
	WHERE KNWLDG_ID = #{knoId}


	SELECT TOP 1 'DMID_' + CAST(CAST(SUBSTRING(KNWLDG_ID, 6, LEN(KNWLDG_ID) - 5) AS BIGINT) + 1 AS VARCHAR)
	FROM XBOLTDLM.COMTNDAMKNOIFM
	ORDER BY KNWLDG_ID DESC;


	SELECT KNWLDG_TY_CODE
	FROM XBOLTDLM.COMTNDAMMAPKNO
	WHERE ORGNZT_ID = #{orgnztId}

mapper.insert:

	    INSERT 
	      INTO  XBOLTDLM.COMTNDAMKNOIFM
	         (  KNWLDG_ID
	         ,  KNWLDG_NM
	         ,	ORGNZT_ID
	         ,  KNWLDG_TY_CODE
	         ,  KNWLDG_CN
	         ,  COLCT_DE
	         ,  OTHBC_AT
	         ,  ATCH_FILE_ID
		     ,	FRST_REGISTER_ID
		     ,	FRST_REGIST_PNTTM
	         ,  LAST_UPDUSR_ID			     	         
	         ,  LAST_UPDT_PNTTM
	         ,  CORP_ID
			 ,  SVC_CI_ID
			 ,  SYMPTON_DESC
			 ,  ROOTCAUSE_DESC
			 ,  KNWLDG_EVL 
	         ) 
	    VALUES  
	         (  #{knoId}
	         ,  #{knoNm}
	         ,  #{project}		         		         
	         ,  #{knoTypeCd}
	         ,  #{knwldgCn}
	         ,  GETDATE()
	         ,  'Y'
	         ,  #{AtchFileId}
	         ,  #{userId}
	         ,  GETDATE()      		 
	         ,  #{userId}
	         ,  GETDATE()
	         ,  #{srArea1}	
	         ,  #{srArea2}
	         ,  #{sympton}
	         ,  #{rootCause}
	         , '1'
	         )

mapper.update:
	
			UPDATE XBOLTDLM.COMTNDAMKNOIFM 
			SET
				KNWLDG_NM = #{knoNm}
			 ,	KNWLDG_CN = #{knwldgCn}
			 ,	ORGNZT_ID = #{project}
			 ,	KNWLDG_TY_CODE = #{knoTypeCd}
	         ,  ATCH_FILE_ID = #{AtchFileId}
	         ,  LAST_UPDUSR_ID = #{userId}			     	         
	         ,  LAST_UPDT_PNTTM = GETDATE()
   			 ,  SYMPTON_DESC = #{sympton}
   			 ,  ROOTCAUSE_DESC = #{rootCause}	 
   			 ,	CORP_ID = #{srArea1}
   			 ,	SVC_CI_ID = #{srArea2}
 			WHERE  KNWLDG_ID = #{knoId}
